#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    long long **dp = (long long **)malloc((n + 2) * sizeof(long long *));
    for (int i = 0; i < n + 2; i++) {
        dp[i] = (long long *)malloc(m * sizeof(long long));
    }
    dp[0][0] = 1;
    for (int i = 0; i < k; i++) {
        int edge0, edge1, edge2, edge3;
        scanf("%d %d %d %d", &edge0, &edge1, &edge2, &edge3);
        dp[edge2][edge3] = (dp[edge2][edge3] + dp[edge0][edge1]) % MOD;
    }
    for (int i = 1; i < n + 1; i++) {
        for (int j = 0; j < m; j++) {
            for (int l = 0; l < m; l++) {
                dp[i + 1][l] = (dp[i + 1][l] + dp[i][j]) % MOD;
            }
        }
    }
    printf("%lld\n", dp[n + 1][0]);
    return 0;
}

